import{_ as a,c as t,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"更新日志: 版本历史 | everything-claude-code","description":"了解 everything-claude-code 的版本历史和重要变更。追踪新功能、安全修复和文档更新，决定是否需要升级。","frontmatter":{"title":"更新日志: 版本历史 | everything-claude-code","sidebarTitle":"看看最近更新了什么","subtitle":"更新日志: 版本历史","description":"了解 everything-claude-code 的版本历史和重要变更。追踪新功能、安全修复和文档更新，决定是否需要升级。","tags":["changelog","updates"],"prerequisite":[],"order":250},"headers":[],"relativePath":"zh/affaan-m/everything-claude-code/changelog/release-notes/index.md","filePath":"zh/affaan-m/everything-claude-code/changelog/release-notes/index.md"}'),l={name:"zh/affaan-m/everything-claude-code/changelog/release-notes/index.md"};function r(d,e,n,s,h,c){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="更新日志-版本历史与变更" tabindex="-1">更新日志：版本历史与变更 <a class="header-anchor" href="#更新日志-版本历史与变更" aria-label="Permalink to &quot;更新日志：版本历史与变更&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>了解每个版本的重要变更</li><li>追踪新功能和修复</li><li>决定是否需要升级</li></ul><h2 id="版本历史" tabindex="-1">版本历史 <a class="header-anchor" href="#版本历史" aria-label="Permalink to &quot;版本历史&quot;">​</a></h2><h3 id="_2026-01-24-安全修复和文档修复" tabindex="-1">2026-01-24 - 安全修复和文档修复 <a class="header-anchor" href="#_2026-01-24-安全修复和文档修复" aria-label="Permalink to &quot;2026-01-24 - 安全修复和文档修复&quot;">​</a></h3><p><strong>修复内容</strong>：</p><ul><li>🔒 <strong>安全修复</strong>：防止 <code>commandExists()</code> 中的命令注入漏洞 <ul><li>使用 <code>spawnSync</code> 替代 <code>execSync</code></li><li>验证输入仅允许字母数字、连字符、下划线、点</li></ul></li><li>📝 <strong>文档修复</strong>：添加 <code>runCommand()</code> 的安全文档警告</li><li>🐛 <strong>XSS 扫描器误报修复</strong>：替换 <code>&lt;script&gt;</code> 和 <code>&lt;binary&gt;</code> 为 <code>[script-name]</code> 和 <code>[binary-name]</code></li><li>📚 <strong>文档修复</strong>：修正 <code>doc-updater.md</code> 中的 <code>npx ts-morph</code> 为正确的 <code>npx tsx scripts/codemaps/generate.ts</code></li></ul><p><strong>影响</strong>：#42, #43, #51</p><hr><h3 id="_2026-01-22-跨平台支持和插件化" tabindex="-1">2026-01-22 - 跨平台支持和插件化 <a class="header-anchor" href="#_2026-01-22-跨平台支持和插件化" aria-label="Permalink to &quot;2026-01-22 - 跨平台支持和插件化&quot;">​</a></h3><p><strong>新功能</strong>：</p><ul><li>🌐 <strong>跨平台支持</strong>：所有 hooks 和脚本重写为 Node.js，支持 Windows、macOS 和 Linux</li><li>📦 <strong>插件打包</strong>：作为 Claude Code 插件分发，支持插件市场安装</li><li>🎯 <strong>包管理器自动检测</strong>：支持 6 种检测优先级 <ul><li>环境变量 <code>CLAUDE_PACKAGE_MANAGER</code></li><li>项目配置 <code>.claude/package-manager.json</code></li><li><code>package.json</code> 的 <code>packageManager</code> 字段</li><li>Lock 文件检测（package-lock.json, yarn.lock, pnpm-lock.yaml, bun.lockb）</li><li>全局配置 <code>~/.claude/package-manager.json</code></li><li>降级到第一个可用的包管理器</li></ul></li></ul><p><strong>修复内容</strong>：</p><ul><li>🔄 <strong>Hook 加载</strong>：自动按约定加载 hooks，移除 <code>plugin.json</code> 中的 hooks 声明</li><li>📌 <strong>Hook 路径</strong>：使用 <code>${CLAUDE_PLUGIN_ROOT}</code> 和相对路径</li><li>🎨 <strong>UI 改进</strong>：添加 star 历史图表和 badge bar</li><li>📖 <strong>Hook 组织</strong>：将 session-end hooks 从 Stop 移至 SessionEnd</li></ul><hr><h3 id="_2026-01-20-功能增强" tabindex="-1">2026-01-20 - 功能增强 <a class="header-anchor" href="#_2026-01-20-功能增强" aria-label="Permalink to &quot;2026-01-20 - 功能增强&quot;">​</a></h3><p><strong>新功能</strong>：</p><ul><li>💾 <strong>Memory Persistence Hooks</strong>：跨会话自动保存和加载上下文</li><li>🧠 <strong>Strategic Compact Hook</strong>：智能上下文压缩建议</li><li>📚 <strong>Continuous Learning Skill</strong>：从会话中自动提取可复用模式</li><li>🎯 <strong>Strategic Compact Skill</strong>：Token 优化策略</li></ul><hr><h3 id="_2026-01-17-初始发布" tabindex="-1">2026-01-17 - 初始发布 <a class="header-anchor" href="#_2026-01-17-初始发布" aria-label="Permalink to &quot;2026-01-17 - 初始发布&quot;">​</a></h3><p><strong>初始功能</strong>：</p><ul><li>✨ 完整的 Claude Code 配置集合</li><li>🤖 9 个专业化 agents</li><li>⚡ 14 个斜杠命令</li><li>📋 8 套规则集</li><li>🔄 自动化 hooks</li><li>🎨 11 个技能库</li><li>🌐 15+ 个 MCP 服务器预配置</li><li>📖 完整的 README 文档</li></ul><hr><h2 id="版本命名说明" tabindex="-1">版本命名说明 <a class="header-anchor" href="#版本命名说明" aria-label="Permalink to &quot;版本命名说明&quot;">​</a></h2><p>本项目不使用传统的语义化版本号，而是采用<strong>日期版本</strong>格式（<code>YYYY-MM-DD</code>）。</p><h3 id="版本类型" tabindex="-1">版本类型 <a class="header-anchor" href="#版本类型" aria-label="Permalink to &quot;版本类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><strong>新功能</strong></td><td>添加新功能或重大改进</td><td><code>feat: add new agent</code></td></tr><tr><td><strong>修复</strong></td><td>修复 bug 或问题</td><td><code>fix: resolve hook loading issue</code></td></tr><tr><td><strong>文档</strong></td><td>文档更新</td><td><code>docs: update README</code></td></tr><tr><td><strong>样式</strong></td><td>格式化或代码风格</td><td><code>style: fix indentation</code></td></tr><tr><td><strong>重构</strong></td><td>代码重构</td><td><code>refactor: simplify hook logic</code></td></tr><tr><td><strong>性能</strong></td><td>性能优化</td><td><code>perf: improve context loading</code></td></tr><tr><td><strong>测试</strong></td><td>测试相关</td><td><code>test: add unit tests</code></td></tr><tr><td><strong>构建</strong></td><td>构建系统或依赖</td><td><code>build: update package.json</code></td></tr><tr><td><strong>撤销</strong></td><td>撤销之前的提交</td><td><code>revert: remove version field</code></td></tr></tbody></table><hr><h2 id="如何获取更新" tabindex="-1">如何获取更新 <a class="header-anchor" href="#如何获取更新" aria-label="Permalink to &quot;如何获取更新&quot;">​</a></h2><h3 id="插件市场更新" tabindex="-1">插件市场更新 <a class="header-anchor" href="#插件市场更新" aria-label="Permalink to &quot;插件市场更新&quot;">​</a></h3><p>如果你通过插件市场安装了 Everything Claude Code：</p><ol><li>打开 Claude Code</li><li>运行 <code>/plugin update everything-claude-code</code></li><li>等待更新完成</li></ol><h3 id="手动更新" tabindex="-1">手动更新 <a class="header-anchor" href="#手动更新" aria-label="Permalink to &quot;手动更新&quot;">​</a></h3><p>如果你手动克隆了仓库：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/plugins/everything-claude-code</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h3 id="从市场安装" tabindex="-1">从市场安装 <a class="header-anchor" href="#从市场安装" aria-label="Permalink to &quot;从市场安装&quot;">​</a></h3><p>首次安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> affaan-m/everything-claude-code</span></span></code></pre></div><hr><h2 id="变更影响分析" tabindex="-1">变更影响分析 <a class="header-anchor" href="#变更影响分析" aria-label="Permalink to &quot;变更影响分析&quot;">​</a></h2><h3 id="安全修复-必须升级" tabindex="-1">安全修复（必须升级） <a class="header-anchor" href="#安全修复-必须升级" aria-label="Permalink to &quot;安全修复（必须升级）&quot;">​</a></h3><ul><li><strong>2026-01-24</strong>：命令注入漏洞修复，强烈建议升级</li></ul><h3 id="功能增强-可选升级" tabindex="-1">功能增强（可选升级） <a class="header-anchor" href="#功能增强-可选升级" aria-label="Permalink to &quot;功能增强（可选升级）&quot;">​</a></h3><ul><li><strong>2026-01-22</strong>：跨平台支持，Windows 用户必须升级</li><li><strong>2026-01-20</strong>：新功能增强，按需升级</li></ul><h3 id="文档更新-无需升级" tabindex="-1">文档更新（无需升级） <a class="header-anchor" href="#文档更新-无需升级" aria-label="Permalink to &quot;文档更新（无需升级）&quot;">​</a></h3><ul><li>文档更新不影响功能，可手动查看 README</li></ul><hr><h2 id="已知问题" tabindex="-1">已知问题 <a class="header-anchor" href="#已知问题" aria-label="Permalink to &quot;已知问题&quot;">​</a></h2><h3 id="当前版本-2026-01-24" tabindex="-1">当前版本（2026-01-24） <a class="header-anchor" href="#当前版本-2026-01-24" aria-label="Permalink to &quot;当前版本（2026-01-24）&quot;">​</a></h3><ul><li>无已知严重问题</li></ul><h3 id="之前版本" tabindex="-1">之前版本 <a class="header-anchor" href="#之前版本" aria-label="Permalink to &quot;之前版本&quot;">​</a></h3><ul><li>2026-01-22 之前：Hooks 加载需要手动配置（已在 2026-01-22 修复）</li><li>2026-01-20 之前：不支持 Windows（已在 2026-01-22 修复）</li></ul><hr><h2 id="贡献与反馈" tabindex="-1">贡献与反馈 <a class="header-anchor" href="#贡献与反馈" aria-label="Permalink to &quot;贡献与反馈&quot;">​</a></h2><h3 id="报告问题" tabindex="-1">报告问题 <a class="header-anchor" href="#报告问题" aria-label="Permalink to &quot;报告问题&quot;">​</a></h3><p>如果你发现了 bug 或有功能建议，请：</p><ol><li>在 <a href="https://github.com/affaan-m/everything-claude-code/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 搜索是否已有类似问题</li><li>如果没有，创建新 Issue，并提供： <ul><li>版本信息</li><li>操作系统</li><li>重现步骤</li><li>预期行为 vs 实际行为</li></ul></li></ol><h3 id="提交-pr" tabindex="-1">提交 PR <a class="header-anchor" href="#提交-pr" aria-label="Permalink to &quot;提交 PR&quot;">​</a></h3><p>欢迎贡献！请查看 <a href="https://github.com/affaan-m/everything-claude-code/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a> 了解详情。</p><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>Everything Claude Code 使用日期版本号（<code>YYYY-MM-DD</code>）</li><li>安全修复（如 2026-01-24）必须升级</li><li>功能增强可按需升级</li><li>插件市场用户使用 <code>/plugin update</code> 更新</li><li>手动安装用户使用 <code>git pull</code> 更新</li><li>报告问题和提交 PR 请遵循项目指南</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../appendix/config-reference/">配置文件详解</a></strong>。</p><p>你会学到：</p><ul><li><code>settings.json</code> 的完整字段说明</li><li>Hooks 配置的高级选项</li><li>MCP 服务器配置详解</li><li>自定义配置的最佳实践</li></ul></blockquote>',64)])])}const p=a(l,[["render",r]]);export{u as __pageData,p as default};
